// Moteur de tarification NeoTravel — 100% déterministe, zéro LLM

const GRILLE_KM = {
  10:250,20:250,30:250,40:320,50:350,60:390,
  70:430,80:500,90:540,100:580,110:620,120:660,
  130:700,140:740,150:780,160:820,170:860,180:900
};

const COEFF_SAISONNALITE = {
  1:-0.07,2:-0.07,3:+0.10,4:+0.10,5:+0.15,6:+0.15,
  7:+0.10,8:-0.07,9:0.00,10:0.00,11:-0.07,12:0.00
};

const COEFF_URGENCE = {
  DD_PRIORITAIRE:+0.10,DD_URGENT:+0.05,DD_NORMAL:-0.05,DD_3MOISETPLUS:-0.10
};

const TRANCHES_CAPACITE = [
  [0,19,-0.05],[19,53,0.00],[53,63,+0.15],[63,67,+0.20],[67,85,+0.40]
];

const MARGE = 0.15;
const TVA = 0.10;
const PRIX_KM_LONG = 2.5;

function arrondir_km(km) {
  return Math.ceil(km / 10) * 10;
}

function prix_base_simple(distance_km) {
  if (distance_km <= 0) throw new Error('La distance doit être supérieure à 0 km.');
  if (distance_km > 850) throw new Error('Distance irréaliste : ' + distance_km + ' km.');
  if (distance_km <= 180) {
    const km_arrondi = arrondir_km(distance_km);
    const prix = GRILLE_KM[km_arrondi];
    if (prix === undefined) throw new Error('Pas de tarif en grille pour ' + km_arrondi + ' km.');
    return { prix, source: 'Grille forfait (' + km_arrondi + ' km)' };
  }
  const prix = (distance_km * 2) * PRIX_KM_LONG;
  return { prix, source: 'Hors grille (' + distance_km + ' km × 2 × ' + PRIX_KM_LONG + ' €/km)' };
}

function get_coeff_saisonnalite(date_depart) {
  const d = new Date(date_depart);
  if (isNaN(d.getTime())) throw new Error('Date de départ invalide : ' + date_depart);
  const mois = d.getMonth() + 1;
  return { coeff: COEFF_SAISONNALITE[mois], label: 'Mois ' + mois + ' → ' + (COEFF_SAISONNALITE[mois] * 100).toFixed(0) + '%' };
}

function get_coeff_urgence(code_urgence) {
  const coeff = COEFF_URGENCE[code_urgence];
  if (coeff === undefined) throw new Error('Code urgence invalide : "' + code_urgence + '". Valeurs acceptées : ' + Object.keys(COEFF_URGENCE).join(', '));
  return { coeff, label: code_urgence + ' → ' + (coeff * 100).toFixed(0) + '%' };
}

function get_coeff_capacite(nb_passagers) {
  if (nb_passagers <= 0) throw new Error('Le nombre de passagers doit être > 0.');
  if (nb_passagers > 85) throw new Error('Capacité max dépassée : ' + nb_passagers + ' passagers (max 85).');
  for (const [min_excl, max_incl, coeff] of TRANCHES_CAPACITE) {
    if (nb_passagers > min_excl && nb_passagers <= max_incl) {
      return { coeff, label: nb_passagers + ' passagers (tranche ' + (min_excl+1) + '–' + max_incl + ') → ' + (coeff * 100).toFixed(0) + '%' };
    }
  }
  throw new Error('Aucune tranche trouvée pour ' + nb_passagers + ' passagers.');
}

function calculer_devis(params) {
  const { nb_passagers, date_depart, date_demande, distance_km, aller_retour, urgence, options = {} } = params;

  if (nb_passagers === undefined || nb_passagers === null) throw new Error('Paramètre manquant : nb_passagers');
  if (!date_depart) throw new Error('Paramètre manquant : date_depart');
  if (!date_demande) throw new Error('Paramètre manquant : date_demande');
  if (distance_km === undefined || distance_km === null) throw new Error('Paramètre manquant : distance_km');
  if (urgence === undefined || urgence === null) throw new Error('Paramètre manquant : urgence');

  const lignes = [];

  const { prix: base_simple, source: source_base } = prix_base_simple(distance_km);
  lignes.push({ libelle: 'Base transfert simple — ' + source_base, montant: base_simple });

  let base = base_simple;
  if (aller_retour) {
    base = base_simple * 2;
    lignes.push({ libelle: 'Aller/Retour (× 2)', montant: base });
  }

  const montant_marge = base * MARGE;
  const apres_marge = base + montant_marge;
  lignes.push({ libelle: 'Marge commerciale (+' + (MARGE * 100).toFixed(0) + '%)', montant: montant_marge });

  const { coeff: cs, label: label_saison } = get_coeff_saisonnalite(date_depart);
  const montant_saison = apres_marge * cs;
  const apres_saison = apres_marge + montant_saison;
  lignes.push({ libelle: 'Saisonnalité — ' + label_saison, montant: montant_saison });

  const { coeff: cu, label: label_urgence } = get_coeff_urgence(urgence);
  const montant_urgence = apres_saison * cu;
  const apres_urgence = apres_saison + montant_urgence;
  lignes.push({ libelle: 'Urgence — ' + label_urgence, montant: montant_urgence });

  const { coeff: cc, label: label_capacite } = get_coeff_capacite(nb_passagers);
  const montant_capacite = apres_urgence * cc;
  const apres_capacite = apres_urgence + montant_capacite;
  lignes.push({ libelle: 'Capacité — ' + label_capacite, montant: montant_capacite });

  let total_options = 0;
  if (options.nb_guides && options.nb_guides > 0) {
    const nb_jours = options.nb_jours || 1;
    const montant_guide = options.nb_guides * 80 * nb_jours;
    total_options += montant_guide;
    lignes.push({ libelle: 'Guide(s) — ' + options.nb_guides + ' × 80€ × ' + nb_jours + ' jour(s)', montant: montant_guide });
  }
  if (options.nb_nuits_chauffeur && options.nb_nuits_chauffeur > 0) {
    const montant_nuit = options.nb_nuits_chauffeur * 120;
    total_options += montant_nuit;
    lignes.push({ libelle: 'Nuit(s) chauffeur — ' + options.nb_nuits_chauffeur + ' × 120€', montant: montant_nuit });
  }
  if (options.peages_inclus) {
    lignes.push({ libelle: 'Péages — inclus au forfait', montant: 0 });
  }

  const prix_ht = Math.round((apres_capacite + total_options) * 100) / 100;
  lignes.push({ libelle: '─── SOUS-TOTAL HT', montant: prix_ht });

  const montant_tva = Math.round(prix_ht * TVA * 100) / 100;
  lignes.push({ libelle: 'TVA (' + (TVA * 100).toFixed(0) + '%)', montant: montant_tva });

  const prix_ttc = Math.round((prix_ht + montant_tva) * 100) / 100;

  return {
    prix_ht, tva: montant_tva, prix_ttc, devise: 'EUR', lignes,
    coefficients: {
      marge: '+' + (MARGE * 100).toFixed(0) + '%',
      saisonnalite: label_saison,
      urgence: label_urgence,
      capacite: label_capacite
    },
    meta: {
      distance_km, aller_retour: aller_retour || false, nb_passagers,
      date_depart, date_demande, calcule_le: new Date().toISOString()
    }
  };
}

// ── EXÉCUTION ──
const donnees = $json.donnees;
return calculer_devis(donnees);

const urgence = $node['AI Agent'].json.donnees.urgence;
const delaiJours = (urgence === 'DD_PRIORITAIRE' || urgence === 'DD_URGENT') ? 2 : 3;
const dateRelance = new Date(Date.now() + delaiJours * 86400000).toISOString().split('T')[0];
return {
  delai_jours: delaiJours,
  date_relance: dateRelance,
  email: $node['AI Agent'].json.donnees.email,
  nom_societe: $node['AI Agent'].json.donnees.nom_societe,
  prix_ttc: $node['Calculer devis'].json.prix_ttc
};
